## Brand Logo Field

A field that captures a brand logo (used by the brand-guide system)

### Usage

```ts
import { CardDef, field, contains } from 'https://cardstack.com/base/card-api';
import BrandLogoField from 'https://cardstack.com/base/brand-logo';

export class Example extends CardDef {
  @field logo = contains(BrandLogoField);
}
```
